Create Comment/Story.code:
// Add a comment / story to a task.
createTaskStory(
  // 1) The task's globally unique id.
  $.data.taskGid,
  {
    // 2) The comment body (HTML supported when html_text is used).
    text: 'Status update: imported from the upstream system.',
  }
);

Create Task.code:
// Create a new task.
createTask({
  // The task's title.
  name: 'Follow up with patient',
  // Long-form description (optional).
  notes: `Imported from upstream system on ${new Date().toISOString()}`,
  // Workspace gid this task lives in.
  workspace: $.configuration.workspaceGid,
  // Optional: place the task into a project on creation.
  projects: [$.data.projectGid],
  // Optional: assign to a user gid.
  assignee: $.data.assigneeGid,
  // Optional ISO date string.
  due_on: '2026-06-01',
});

Update Task.code:
// Update properties on an existing task.
updateTask(
  // 1) Task gid.
  $.data.taskGid,
  // 2) Fields to change.
  {
    name: 'Updated task title',
    completed: true,
    notes: 'Closed after upstream sync.',
  }
);

API Request (Beta).code:
// Make an arbitrary request against the Asana API.
// Path is relative to the Asana base URL.
request('/workspaces', {
  method: 'GET',
  query: { limit: 10 },
});

Find All Tasks From Project.code:
// List tasks in a project.
getTasks(
  // 1) Project gid.
  $.data.projectGid,
  // 2) Query params.
  {
    // Fields to return per task.
    opt_fields: 'name,notes,assignee,completed,due_on',
    // Cap the result size.
    limit: 100,
  }
);

Find Tasks in Workspace.code:
// Search tasks across a workspace using Asana's typeahead/search API.
// Note: this endpoint requires a premium Asana plan.
searchTask(
  // 1) The search term (matches task name).
  $.data.searchTerm,
  // 2) Query params (assignee, completed, etc).
  {
    'assignee.any': $.data.assigneeGid,
    completed: false,
  }
);
